import os
import re
from flask import Flask, request, jsonify
import psycopg2
import psycopg2.extras

app = Flask(__name__)

# Database configuration from environment variables
DB_CONFIG = {
    'host': os.environ.get('DB_HOST', 'localhost'),
    'port': os.environ.get('DB_PORT', '5432'),
    'dbname': os.environ.get('DB_NAME', 'analytics'),
    'user': os.environ.get('DB_USER', 'postgres'),
    'password': os.environ.get('DB_PASSWORD', 'postgres'),
}

# Whitelist of allowed tables and columns for security
ALLOWED_TABLES = os.environ.get('ALLOWED_TABLES', '').split(',') if os.environ.get('ALLOWED_TABLES') else []
ALLOWED_OPERATORS = {'=', '!=', '<', '>', '<=', '>=', 'LIKE', 'ILIKE', 'IN', 'NOT IN', 'IS NULL', 'IS NOT NULL', 'BETWEEN'}
ALLOWED_AGGREGATES = {'COUNT', 'SUM', 'AVG', 'MIN', 'MAX'}
ALLOWED_ORDER_DIRECTIONS = {'ASC', 'DESC'}

MAX_LIMIT = 10000
DEFAULT_LIMIT = 100


def get_db_connection():
    """Create and return a database connection."""
    conn = psycopg2.connect(**DB_CONFIG)
    return conn


def validate_identifier(identifier):
    """Validate that an identifier (table/column name) is safe."""
    pattern = re.compile(r'^[a-zA-Z_][a-zA-Z0-9_.]*$')
    if not pattern.match(identifier):
        raise ValueError(f"Invalid identifier: {identifier}")
    return identifier


def validate_table_name(table_name):
    """Validate table name against whitelist if configured."""
    validate_identifier(table_name)
    if ALLOWED_TABLES and table_name not in ALLOWED_TABLES:
        raise ValueError(f"Table '{table_name}' is not in the allowed tables list")
    return table_name


def get_table_columns(conn, table_name):
    """Fetch actual column names from the database for validation."""
    schema = 'public'
    actual_table = table_name
    if '.' in table_name:
        schema, actual_table = table_name.split('.', 1)

    with conn.cursor() as cur:
        cur.execute(
            """
            SELECT column_name 
            FROM information_schema.columns 
            WHERE table_schema = %s AND table_name = %s
            """,
            (schema, actual_table)
        )
        return {row[0] for row in cur.fetchall()}


def validate_columns(columns, valid_columns, table_name):
    """Validate that requested columns exist in the table."""
    for col in columns:
        # Handle aggregate functions
        base_col = col
        for agg in ALLOWED_AGGREGATES:
            if col.upper().startswith(f"{agg}(") and col.endswith(')'):
                base_col = col[len(agg)+1:-1].strip()
                break

        if base_col == '*':
            continue

        validate_identifier(base_col)
        if base_col.lower() not in {c.lower() for c in valid_columns}:
            raise ValueError(f"Column '{base_col}' does not exist in table '{table_name}'")


def build_select_clause(columns, valid_columns, table_name):
    """Build the SELECT clause with optional aggregates."""
    if not columns:
        return '*', []

    validate_columns(columns, valid_columns, table_name)

    select_parts = []
    for col in columns:
        # Check for aggregate functions
        is_aggregate = False
        for agg in ALLOWED_AGGREGATES:
            if col.upper().startswith(f"{agg}(") and col.endswith(')'):
                inner_col = col[len(agg)+1:-1].strip()
                if inner_col == '*':
                    select_parts.append(f"{agg}(*)")
                else:
                    select_parts.append(f"{agg}({psycopg2.sql.Identifier(inner_col).as_string(None) if False else quote_identifier(inner_col)})")
                is_aggregate = True
                break

        if not is_aggregate:
            select_parts.append(quote_identifier(col))

    return ', '.join(select_parts), []


def quote_identifier(identifier):
    """Safely quote a SQL identifier."""
    validate_identifier(identifier)
    # Double any existing double quotes and wrap in double quotes
    return '"' + identifier.replace('"', '""') + '"'


def build_where_clause(filters, valid_columns, table_name):
    """Build WHERE clause from filter conditions."""
    if not filters:
        return '', []

    conditions = []
    params = []

    for f in filters:
        column = f.get('column')
        operator = f.get('operator', '=').upper()
        value = f.get('value')
        logic = f.get('logic', 'AND').upper()

        if logic not in ('AND', 'OR'):
            raise ValueError(f"Invalid logic operator: {logic}")

        if not column:
            raise ValueError("Filter must include a 'column' field")

        validate_identifier(column)
        if column.lower() not in {c.lower() for c in valid_columns}:
            raise ValueError(f"Column '{column}' does not exist in table '{table_name}'")

        if operator not in ALLOWED_OPERATORS:
            raise ValueError(f"Operator '{operator}' is not allowed. Allowed: {ALLOWED_OPERATORS}")

        col_quoted = quote_identifier(column)

        if operator in ('IS NULL', 'IS NOT NULL'):
            condition = f"{col_quoted} {operator}"
        elif operator == 'BETWEEN':
            if not isinstance(value, (list, tuple)) or len(value) != 2:
                raise ValueError("BETWEEN operator requires a list of two values")
            condition = f"{col_quoted} BETWEEN %s AND %s"
            params.extend(value)
        elif operator in ('IN', 'NOT IN'):
            if not isinstance(value, (list, tuple)):
                raise ValueError(f"{operator} operator requires a list of values")
            placeholders = ', '.join(['%s'] * len(value))
            condition = f"{col_quoted} {operator} ({placeholders})"
            params.extend(value)
        else:
            condition = f"{col_quoted} {operator} %s"
            params.append(value)

        if conditions:
            conditions.append(f"{logic} {condition}")
        else:
            conditions.append(condition)

    where_clause = 'WHERE ' + ' '.join(conditions)
    return where_clause, params


def build_group_by_clause(group_by, valid_columns, table_name):
    """Build GROUP BY clause."""
    if not group_by:
        return ''

    validate_columns(group_by, valid_columns, table_name)
    cols = ', '.join(quote_identifier(col) for col in group_by)
    return f'GROUP BY {cols}'


def build_having_clause(having_filters, valid_columns, table_name):
    """Build HAVING clause for aggregate filters."""
    if not having_filters:
        return '', []

    conditions = []
    params = []

    for f in having_filters:
        aggregate = f.get('aggregate', '').upper()
        column = f.get('column', '*')
        operator = f.get('operator', '=').upper()
        value = f.get('value')

        if aggregate not in ALLOWED_AGGREGATES:
            raise ValueError(f"Aggregate '{aggregate}' is not allowed")

        if operator not in ALLOWED_OPERATORS:
            raise ValueError(f"Operator '{operator}' is not allowed")

        if column != '*':
            validate_identifier(column)
            if column.lower() not in {c.lower() for c in valid_columns}:
                raise ValueError(f"Column '{column}' does not exist in table '{table_name}'")
            agg_expr = f"{aggregate}({quote_identifier(column)})"
        else:
            agg_expr = f"{aggregate}(*)"

        condition = f"{agg_expr} {operator} %s"
        conditions.append(condition)
        params.append(value)

    having_clause = 'HAVING ' + ' AND '.join(conditions)
    return having_clause, params


def build_order_by_clause(order_by, valid_columns, table_name):
    """Build ORDER BY clause."""
    if not order_by:
        return ''

    parts = []
    for item in order_by:
        if isinstance(item, str):
            column = item
            direction = 'ASC'
        elif isinstance(item, dict):
            column = item.get('column')
            direction = item.get('direction', 'ASC').upper()
        else:
            raise ValueError("Invalid order_by format")

        validate_identifier(column)
        if column.lower() not in {c.lower() for c in valid_columns}:
            raise ValueError(f"Column '{column}' does not exist in table '{table_name}'")

        if direction not in ALLOWED_ORDER_DIRECTIONS:
            raise ValueError(f"Invalid order direction: {direction}")

        nulls = ''
        if isinstance(item, dict) and 'nulls' in item:
            nulls_val = item['nulls'].upper()
            if nulls_val in ('FIRST', 'LAST'):
                nulls = f' NULLS {nulls_val}'

        parts.append(f"{quote_identifier(column)} {direction}{nulls}")

    return 'ORDER BY ' + ', '.join(parts)


def build_join_clause(joins, conn):
    """Build JOIN clauses."""
    if not joins:
        return '', []

    join_parts = []
    for j in joins:
        join_type = j.get('type', 'INNER').upper()
        if join_type not in ('INNER', 'LEFT', 'RIGHT', 'FULL', 'CROSS', 'LEFT OUTER', 'RIGHT OUTER', 'FULL OUTER'):
            raise ValueError(f"Invalid join type: {join_type}")

        join_table = j.get('table')
        validate_table_name(join_table)

        on_left = j.get('on_left')
        on_right = j.get('on_right')

        validate_identifier(on_left)
        validate_identifier(on_right)

        # Allow dotted notation for join conditions (table.column)
        on_left_parts = on_left.split('.')
        on_right_parts = on_right.split('.')

        left_quoted = '.'.join(quote_identifier(p) for p in on_left_parts)
        right_quoted = '.'.join(quote_identifier(p) for p in on_right_parts)

        join_parts.append(
            f"{join_type} JOIN {quote_identifier(join_table)} ON {left_quoted} = {right_quoted}"
        )

    return ' '.join(join_parts), []


@app.route('/api/query', methods=['POST'])
def dynamic_query():
    """
    Execute a dynamic query based on JSON input.

    Expected JSON body:
    {
        "table": "table_name",
        "columns": ["col1", "col2", "COUNT(col3)"],
        "filters": [
            {"column": "col1", "operator": "=", "value": "some_value"},
            {"column": "col2", "operator": ">", "value": 100, "logic": "AND"},
            {"column": "col3", "operator": "IN", "value": [1, 2, 3]},
            {"column": "col4", "operator": "BETWEEN", "value": [10, 50]},
            {"column": "col5", "operator": "IS NOT NULL"}
        ],
        "joins": [
            {
                "type": "LEFT",
                "table": "other_table",
                "on_left": "table_name.id",
                "on_right": "other_table.table_id"
            }
        ],
        "group_by": ["col1"],
        "having": [
            {"aggregate": "COUNT", "column": "col3", "operator": ">", "value": 5}
        ],
        "order_by": [
            {"column": "col1", "direction": "ASC"},
            {"column": "col2", "direction": "DESC", "nulls": "LAST"}
        ],
        "limit": 100,
        "offset": 0,
        "distinct": false
    }
    """
    try:
        data = request.get_json()
        if not data:
            return jsonify({'error': 'Request body must be JSON'}), 400

        # Required: table name
        table_name = data.get('table')
        if not table_name:
            return jsonify({'error': 'Table name is required'}), 400

        validate_table_name(table_name)

        # Optional parameters
        columns = data.get('columns', [])
        filters = data.get('filters', [])
        joins = data.get('joins', [])
        group_by = data.get('group_by', [])
        having_filters = data.get('having', [])
        order_by = data.get('order_by', [])
        limit = data.get('limit', DEFAULT_LIMIT)
        offset = data.get('offset', 0)
        distinct = data.get('distinct', False)

        # Validate limit and offset
        if not isinstance(limit, int) or limit < 0:
            return jsonify({'error': 'Limit must be a non-negative integer'}), 400
        if limit > MAX_LIMIT:
            limit = MAX_LIMIT
        if not isinstance(offset, int) or offset < 0:
            return jsonify({'error': 'Offset must be a non-negative integer'}), 400

        conn = get_db_connection()
        try:
            # Get valid columns for the table
            valid_columns = get_table_columns(conn, table_name)
            if not valid_columns:
                return jsonify({'error': f"Table '{table_name}' not found or has no columns"}), 404

            # Also get columns from joined tables
            all_valid_columns = set(valid_columns)
            for j in joins:
                join_table = j.get('table')
                if join_table:
                    validate_table_name(join_table)
                    join_cols = get_table_columns(conn, join_table)
                    all_valid_columns.update(join_cols)

            # Build query parts
            select_clause, select_params = build_select_clause(columns, all_valid_columns, table_name)
            join_clause, join_params = build_join_clause(joins, conn)
            where_clause, where_params = build_where_clause(filters, all_valid_columns, table_name)
            group_by_clause = build_group_by_clause(group_by, all_valid_columns, table_name)
            having_clause, having_params = build_having_clause(having_filters, all_valid_columns, table_name)
            order_by_clause = build_order_by_clause(order_by, all_valid_columns, table_name)

            # Construct the full query
            distinct_keyword = 'DISTINCT ' if distinct else ''
            table_quoted = quote_identifier(table_name)

            query = f"SELECT {distinct_keyword}{select_clause} FROM {table_quoted}"

            if join_clause:
                query += f" {join_clause}"
            if where_clause:
                query += f" {where_clause}"
            if group_by_clause:
                query += f" {group_by_clause}"
            if having_clause:
                query += f" {having_clause}"
            if order_by_clause:
                query += f" {order_by_clause}"

            query += f" LIMIT %s OFFSET %s"

            # Combine all parameters
            all_params = select_params + join_params + where_params + having_params + [limit, offset]

            # Execute query
            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                cur.execute(query, all_params)
                rows = cur.fetchall()

                # Get column names from cursor description
                column_names = [desc[0] for desc in cur.description] if cur.description else []

            # Get total count (without limit/offset)
            count_query = f"SELECT COUNT(*) as total FROM {table_quoted}"
            if join_clause:
                count_query += f" {join_clause}"
            if where_clause:
                count_query += f" {where_clause}"
            if group_by_clause:
                # When GROUP BY is used, count the number of groups
                count_query = f"SELECT COUNT(*) as total FROM (SELECT 1 FROM {table_quoted}"
                if join_clause:
                    count_query += f" {join_clause}"
                if where_clause:
                    count_query += f" {where_clause}"
                count_query += f" {group_by_clause}"
                if having_clause:
                    count_query += f" {having_clause}"
                count_query += ") as subquery"
                count_params = join_params + where_params + having_params
            else:
                count_params = join_params + where_params

            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                cur.execute(count_query, count_params)
                total = cur.fetchone()['total']

            # Convert rows to serializable format
            result_rows = []
            for row in rows:
                result_row = {}
                for key, value in row.items():
                    if hasattr(value, 'isoformat'):
                        result_row[key] = value.isoformat()
                    elif isinstance(value, memoryview):
                        result_row[key] = bytes(value).hex()
                    else:
                        result_row[key] = value
                result_rows.append(result_row)

            response = {
                'success': True,
                'data': result_rows,
                'metadata': {
                    'table': table_name,
                    'columns': column_names,
                    'total_records': total,
                    'returned_records': len(result_rows),
                    'limit': limit,
                    'offset': offset,
                    'query': query  # For debugging - remove in production
                }
            }

            return jsonify(response), 200

        finally:
            conn.close()

    except ValueError as e:
        return jsonify({'error': str(e), 'success': False}), 400
    except psycopg2.Error as e:
        return jsonify({'error': f'Database error: {str(e)}', 'success': False}), 500
    except Exception as e:
        return jsonify({'error': f'Internal server error: {str(e)}', 'success': False}), 500


@app.route('/api/tables', methods=['GET'])
def list_tables():
    """List all available tables."""
    try:
        conn = get_db_connection()
        try:
            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                cur.execute("""
                    SELECT table_schema, table_name, table_type
                    FROM information_schema.tables
                    WHERE table_schema NOT IN ('pg_catalog', 'information_schema')
                    ORDER BY table_schema, table_name
                """)
                tables = cur.fetchall()

            # Filter by allowed tables if configured
            if ALLOWED_TABLES:
                tables = [t for t in tables if t['table_name'] in ALLOWED_TABLES
                          or f"{t['table_schema']}.{t['table_name']}" in ALLOWED_TABLES]

            return jsonify({
                'success': True,
                'tables': [dict(t) for t in tables]
            }), 200
        finally:
            conn.close()

    except psycopg2.Error as e:
        return jsonify({'error': f'Database error: {str(e)}', 'success': False}), 500


@app.route('/api/tables/<table_name>/columns', methods=['GET'])
def list_columns(table_name):
    """List columns for a specific table."""
    try:
        validate_table_name(table_name)

        schema = 'public'
        actual_table = table_name
        if '.' in table_name:
            schema, actual_table = table_name.split('.', 1)

        conn = get_db_connection()
        try:
            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                cur.execute("""
                    SELECT column_name, data_type, is_nullable, column_default,
                           character_maximum_length, numeric_precision, numeric_scale
                    FROM information_schema.columns
                    WHERE table_schema = %s AND table_name = %s
                    ORDER BY ordinal_position
                """, (schema, actual_table))
                columns = cur.fetchall()

            if not columns:
                return jsonify({'error': f"Table '{table_name}' not found", 'success': False}), 404

            return jsonify({
                'success': True,
                'table': table_name,
                'columns': [dict(c) for c in columns]
            }), 200
        finally:
            conn.close()

    except ValueError as e:
        return jsonify({'error': str(e), 'success': False}), 400
    except psycopg2.Error as e:
        return jsonify({'error': f'Database error: {str(e)}', 'success': False}), 500


@app.route('/api/tables/<table_name>/stats', methods=['GET'])
def table_stats(table_name):
    """Get basic statistics for a table."""
    try:
        validate_table_name(table_name)

        conn = get_db_connection()
        try:
            table_quoted = quote_identifier(table_name)

            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                # Row count
                cur.execute(f"SELECT COUNT(*) as row_count FROM {table_quoted}")
                row_count = cur.fetchone()['row_count']

                # Column count and types
                schema = 'public'
                actual_table = table_name
                if '.' in table_name:
                    schema, actual_table = table_name.split('.', 1)

                cur.execute("""
                    SELECT data_type, COUNT(*) as count
                    FROM information_schema.columns
                    WHERE table_schema = %s AND table_name = %s
                    GROUP BY data_type
                """, (schema, actual_table))
                column_types = cur.fetchall()

            return jsonify({
                'success': True,
                'table': table_name,
                'stats': {
                    'row_count': row_count,
                    'column_type_distribution': [dict(ct) for ct in column_types]
                }
            }), 200
        finally:
            conn.close()

    except ValueError as e:
        return jsonify({'error': str(e), 'success': False}), 400
    except psycopg2.Error as e:
        return jsonify({'error': f'Database error: {str(e)}', 'success': False}), 500


@app.route('/api/query/aggregate', methods=['POST'])
def aggregate_query():
    """
    Execute an aggregate query.

    Expected JSON body:
    {
        "table": "table_name",
        "aggregates": [
            {"function": "COUNT", "column": "*", "alias": "total_count"},
            {"function": "AVG", "column": "price", "alias": "avg_price"},
            {"function": "SUM", "column": "quantity", "alias": "total_quantity"}
        ],
        "group_by": ["category", "status"],
        "filters": [...],
        "having": [...],
        "order_by": [...],
        "limit": 100
    }
    """
    try:
        data = request.get_json()
        if not data:
            return jsonify({'error': 'Request body must be JSON'}), 400

        table_name = data.get('table')
        if not table_name:
            return jsonify({'error': 'Table name is required'}), 400

        validate_table_name(table_name)

        aggregates = data.get('aggregates', [])
        if not aggregates:
            return jsonify({'error': 'At least one aggregate function is required'}), 400

        group_by = data.get('group_by', [])
        filters = data.get('filters', [])
        having_filters = data.get('having', [])
        order_by = data.get('order_by', [])
        limit = data.get('limit', DEFAULT_LIMIT)

        if not isinstance(limit, int) or limit < 0:
            return jsonify({'error': 'Limit must be a non-negative integer'}), 400
        if limit > MAX_LIMIT:
            limit = MAX_LIMIT

        conn = get_db_connection()
        try:
            valid_columns = get_table_columns(conn, table_name)
            if not valid_columns:
                return jsonify({'error': f"Table '{table_name}' not found"}), 404

            # Build SELECT clause from aggregates and group_by columns
            select_parts = []

            # Add group_by columns to select
            for col in group_by:
                validate_identifier(col)
                if col.lower() not in {c.lower() for c in valid_columns}:
                    raise ValueError(f"Column '{col}' does not exist in table '{table_name}'")
                select_parts.append(quote_identifier(col))

            # Add aggregate functions
            for agg in aggregates:
                func = agg.get('function', '').upper()
                column = agg.get('column', '*')
                alias = agg.get('alias', f"{func.lower()}_{column}")

                if func not in ALLOWED_AGGREGATES:
                    raise ValueError(f"Aggregate function '{func}' is not allowed")

                validate_identifier(alias)

                if column == '*':
                    select_parts.append(f"{func}(*) AS {quote_identifier(alias)}")
                else:
                    validate_identifier(column)
                    if column.lower() not in {c.lower() for c in valid_columns}:
                        raise ValueError(f"Column '{column}' does not exist")
                    select_parts.append(f"{func}({quote_identifier(column)}) AS {quote_identifier(alias)}")

            select_clause = ', '.join(select_parts)
            table_quoted = quote_identifier(table_name)

            # Build other clauses
            where_clause, where_params = build_where_clause(filters, valid_columns, table_name)
            group_by_clause = build_group_by_clause(group_by, valid_columns, table_name)
            having_clause, having_params = build_having_clause(having_filters, valid_columns, table_name)

            # Build order by - allow ordering by aliases too
            order_clause = ''
            if order_by:
                order_parts = []
                alias_names = {agg.get('alias', f"{agg.get('function', '').lower()}_{agg.get('column', '*')}") for agg in aggregates}
                all_valid = valid_columns.union(alias_names)
                for item in order_by:
                    if isinstance(item, str):
                        col = item
                        direction = 'ASC'
                    elif isinstance(item, dict):
                        col = item.get('column')
                        direction = item.get('direction', 'ASC').upper()
                    else:
                        raise ValueError("Invalid order_by format")

                    validate_identifier(col)
                    if direction not in ALLOWED_ORDER_DIRECTIONS:
                        raise ValueError(f"Invalid order direction: {direction}")
                    order_parts.append(f"{quote_identifier(col)} {direction}")
                order_clause = 'ORDER BY ' + ', '.join(order_parts)

            query = f"SELECT {select_clause} FROM {table_quoted}"
            if where_clause:
                query += f" {where_clause}"
            if group_by_clause:
                query += f" {group_by_clause}"
            if having_clause:
                query += f" {having_clause}"
            if order_clause:
                query += f" {order_clause}"
            query += f" LIMIT %s"

            all_params = where_params + having_params + [limit]

            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                cur.execute(query, all_params)
                rows = cur.fetchall()
                column_names = [desc[0] for desc in cur.description] if cur.description else []

            result_rows = []
            for row in rows:
                result_row = {}
                for key, value in row.items():
                    if hasattr(value, 'isoformat'):
                        result_row[key] = value.isoformat()
                    else:
                        result_row[key] = value
                result_rows.append(result_row)

            return jsonify({
                'success': True,
                'data': result_rows,
                'metadata': {
                    'table': table_name,
                    'columns': column_names,
                    'returned_records': len(result_rows),
                    'query': query
                }
            }), 200

        finally:
            conn.close()

    except ValueError as e:
        return jsonify({'error': str(e), 'success': False}), 400
    except psycopg2.Error as e:
        return jsonify({'error': f'Database error: {str(e)}', 'success': False}), 500
    except Exception as e:
        return jsonify({'error': f'Internal server error: {str(e)}', 'success': False}), 500


@app.route('/api/query/distinct', methods=['POST'])
def distinct_values():
    """
    Get distinct values for a column.

    Expected JSON body:
    {
        "table": "table_name",
        "column": "column_name",
        "filters": [...],
        "limit": 1000
    }
    """
    try:
        data = request.get_json()
        if not data:
            return jsonify({'error': 'Request body must be JSON'}), 400

        table_name = data.get('table')
        column = data.get('column')
        filters = data.get('filters', [])
        limit = data.get('limit', 1000)

        if not table_name or not column:
            return jsonify({'error': 'Table name and column are required'}), 400

        validate_table_name(table_name)
        validate_identifier(column)

        if not isinstance(limit, int) or limit < 0:
            return jsonify({'error': 'Limit must be a non-negative integer'}), 400
        if limit > MAX_LIMIT:
            limit = MAX_LIMIT

        conn = get_db_connection()
        try:
            valid_columns = get_table_columns(conn, table_name)
            if column.lower() not in {c.lower() for c in valid_columns}:
                raise ValueError(f"Column '{column}' does not exist in table '{table_name}'")

            table_quoted = quote_identifier(table_name)
            col_quoted = quote_identifier(column)

            where_clause, where_params = build_where_clause(filters, valid_columns, table_name)

            query = f"SELECT DISTINCT {col_quoted}, COUNT(*) as count FROM {table_quoted}"
            if where_clause:
                query += f" {where_clause}"
            query += f" GROUP BY {col_quoted} ORDER BY count DESC LIMIT %s"

            all_params = where_params + [limit]

            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                cur.execute(query, all_params)
                rows = cur.fetchall()

            result_rows = []
            for row in rows:
                result_row = {}
                for key, value in row.items():
                    if hasattr(value, 'isoformat'):
                        result_row[key] = value.isoformat()
                    else:
                        result_row[key] = value
                result_rows.append(result_row)

            return jsonify({
                'success': True,
                'table': table_name,
                'column': column,
                'distinct_values': result_rows,
                'count': len(result_rows)
            }), 200

        finally:
            conn.close()

    except ValueError as e:
        return jsonify({'error': str(e), 'success': False}), 400
    except psycopg2.Error as e:
        return jsonify({'error': f'Database error: {str(e)}', 'success': False}), 500
    except Exception as e:
        return jsonify({'error': f'Internal server error: {str(e)}', 'success': False}), 500


@app.route('/api/health', methods=['GET'])
def health_check():
    """Health check endpoint."""
    try:
        conn = get_db_connection()
        with conn.cursor() as cur:
            cur.execute('SELECT 1')
        conn.close()
        return jsonify({'status': 'healthy', 'database': 'connected'}), 200
    except Exception as e:
        return jsonify({'status': 'unhealthy', 'database': str(e)}), 503


